pair A, B, C, K;
A = (0, 8);
B = (-7, 0);
C = (6, 0);
K = (0, 0);
draw(A--B--C--cycle);
draw(A--K);
label("$A$", A, N);
label("$B$", B, SW);
label("$C$", C, SE);
label("$K$", K, NE);
label("10", C--A, NE);
label("7", B--K, N);
label("13", B--C, S);
