dot(a);
dot(b);
dot(c);
dot(d);
dot(e);
dot(f);
dot(g);
dot(h);
dot(i);
dot(j);
dot(k);
dot(l);
dot(m);
dot(n);
dot(o);
dot(p);
draw(a--b--g--c--d--h--l--k--o--j--i--e--a);
